// Filter: only DispatchTrack report emails
// From: DispatchTrack <no-reply@dtmail.dispatchtrack.io>
// Subject: "Reporte excel 2026-02-25 - Paris"
const subject = ($json.subject || '').toLowerCase();
const from = ($json.from || '').toLowerCase();

if (from.includes('dispatchtrack') && subject.includes('reporte excel')) {
  return [$input.first()];
}
return [];

// Extract direct download link from DispatchTrack email HTML body
// Link pattern: https://cluster-1.dispatchtrack.com/files/1/669607
const html = $json.html || $json.textHtml || $json.body || '';
const text = $json.text || $json.textPlain || '';
const content = html || text;

const linkPattern = /https?:\/\/cluster[^\s"'<>]*\.dispatchtrack\.com\/files\/[^\s"'<>]+/gi;
const matches = content.match(linkPattern);

if (!matches || matches.length === 0) {
  throw new Error('No DispatchTrack download link found in email body');
}

return [{ json: { download_url: matches[0] } }];

// DispatchTrack XLSX: headerRow=true, one row per carton/product
// Group rows by 'Orden' column — multiple rows per order
const items = $input.all();
const OPERATOR_ID = '92dc5797-047d-458d-bbdb-63f18c0dd1e7';
const CLIENT_ID = 'acf3d096-1ff6-4157-9b69-cab6e6a5789f';

function cleanPhone(phone) {
  if (!phone) return '';
  let c = String(phone).replace(/[\s\-\.\(\)]/g, '');
  if (/^9\d{8}$/.test(c)) c = '+56' + c;
  else if (/^569\d{8}$/.test(c)) c = '+' + c;
  else if (/^56\d{9}$/.test(c)) c = '+' + c;
  return c || '';
}

function val(row, key) {
  const v = row[key];
  if (v === null || v === undefined) return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}

function reqVal(row, key, fallback) {
  const v = val(row, key);
  return v || fallback || '';
}

function parseDate(dateStr) {
  if (!dateStr) return new Date().toISOString().slice(0, 10);
  const m = String(dateStr).match(/^(\d{4}-\d{2}-\d{2})/);
  return m ? m[1] : new Date().toISOString().slice(0, 10);
}

const ordersMap = new Map();
const packages = [];
const errors = [];

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const orden = val(row, 'Orden');

  if (!orden) {
    errors.push({ row: i + 1, reason: 'Missing Orden' });
    continue;
  }

  if (!ordersMap.has(orden)) {
    ordersMap.set(orden, {
      operator_id: OPERATOR_ID,
      order_number: orden,
      external_load_id: val(row, 'Identificador ruta'),
      delivery_date: parseDate(val(row, 'Fecha estimada')),
      status_detail: val(row, 'Estado'),
      customer_name: reqVal(row, 'Nombre cliente', 'Sin nombre'),
      delivery_address: reqVal(row, 'Dirección cliente', reqVal(row, 'Direccion cliente', 'Sin dirección')),
      customer_phone: cleanPhone(val(row, 'Teléfono cliente') || val(row, 'Telefono cliente')),
      comuna: reqVal(row, 'Desc_Comuna', 'Sin comuna'),
      retailer_name: 'Paris',
      imported_via: 'EMAIL',
      tenant_client_id: CLIENT_ID,
      imported_at: new Date().toISOString(),
      raw_data: row,
      metadata: {
        customer_email: val(row, 'Correo electrónico cliente') || val(row, 'Correo electronico cliente'),
        latitude: val(row, 'Latitud dirección') || val(row, 'Latitud direccion'),
        longitude: val(row, 'Longitud dirección') || val(row, 'Longitud direccion'),
        is_prime: val(row, 'isPrime'),
        delivery_guide_url: val(row, 'URLGUIA'),
        load_guide_url: val(row, 'URLCARGA'),
        rut: val(row, 'Id cliente')
      }
    });
  }

  // Each row = one carton/product
  const cartonId = val(row, 'CARTONID');
  if (cartonId) {
    packages.push({
      operator_id: OPERATOR_ID,
      order_number: orden,
      label: cartonId,
      sku_items: [{
        sku: val(row, 'Código del producto') || val(row, 'Codigo del producto') || '',
        description: val(row, 'Nombre del producto') || ''
      }],
      raw_data: row
    });
  }
}

const orders = Array.from(ordersMap.values());

if (orders.length === 0) {
  throw new Error('No valid orders from ' + items.length + ' rows (' + errors.length + ' errors)');
}

return [{ json: {
  orders,
  packages,
  rows_processed: items.length,
  orders_count: orders.length,
  packages_count: packages.length,
  rows_skipped: errors.length,
  errors: errors.slice(0, 20),
  operator_id: OPERATOR_ID,
  client_id: CLIENT_ID
}}];

// AC1/AC2: Map DispatchTrack Estado to delivery_attempts records
const OPERATOR_ID = '92dc5797-047d-458d-bbdb-63f18c0dd1e7';

const ESTADO_MAP = {
  'Entregado': { status: 'success', failure_reason: null },
  'Entregado con novedad': { status: 'success', failure_reason: null },
  'No Entregado': { status: 'failed', failure_reason: 'No Entregado' },
  'Fallido': { status: 'failed', failure_reason: 'Fallido' },
  'Ausente': { status: 'failed', failure_reason: 'Ausente' },
  'Dirección incorrecta': { status: 'failed', failure_reason: 'Dirección incorrecta' },
  'Rechazado': { status: 'failed', failure_reason: 'Rechazado' },
  'Devuelto': { status: 'returned', failure_reason: 'Devuelto' },
  'Devolución': { status: 'returned', failure_reason: 'Devolución' },
};

const NON_TERMINAL = new Set(['Ruta troncal', 'Reagendado']);

const orders = $input.all().map(i => i.json);
const attempts = [];
let skipped_count = 0;
let mapped_count = 0;

for (const order of orders) {
  const estado = order.status_detail;
  if (!estado) { skipped_count++; continue; }

  const mapping = ESTADO_MAP[estado];
  if (!mapping) {
    if (!NON_TERMINAL.has(estado)) {
      console.warn(`[MapDeliveryAttempts] Unknown Estado: "${estado}" for order ${order.order_number}`);
    }
    skipped_count++;
    continue;
  }

  // AC2: preserve full datetime from raw_data (delivery_date is date-only)
  const rawData = order.raw_data || {};
  const fechaEstimada = rawData['Fecha estimada'] || order.delivery_date || null;

  attempts.push({
    operator_id: OPERATOR_ID,
    order_id: order.id,
    attempt_number: 1,
    status: mapping.status,
    failure_reason: mapping.failure_reason,
    attempted_at: fechaEstimada,
    driver_id: null,
  });
  mapped_count++;
}

return [{ json: { attempts, mapped_count, skipped_count } }];

// Map order_number -> order_id from UPSERT Orders response
// Reads directly from UPSERT Orders (not $input) so it works
// regardless of whether UPSERT Delivery Attempts succeeded or failed.
const orders = $('UPSERT Orders').all().map(item => item.json);
const packages = $('Map & Validate').first().json.packages;

const orderIds = {};
for (const o of orders) {
  if (o.order_number && o.id) {
    orderIds[o.order_number] = o.id;
  }
}

const linked = packages
  .filter(p => orderIds[p.order_number])
  .map(p => ({
    operator_id: p.operator_id,
    order_id: orderIds[p.order_number],
    label: p.label,
    sku_items: p.sku_items,
    raw_data: p.raw_data
  }));

return [{ json: {
  packages: linked,
  orders_upserted: orders.length,
  packages_count: linked.length
}}];

const mapData = $('Map & Validate').first().json;
const linkData = $('Link Packages').first().json;
const jobId = $('Create Job Record').first().json.id;

// AC6: delivery_attempts counts
let delivery_attempts_upserted = 0;
let delivery_attempts_skipped = 0;
let delivery_attempts_error = null;

try {
  const daMap = $('Map Delivery Attempts').first().json;
  delivery_attempts_upserted = daMap.mapped_count || 0;
  delivery_attempts_skipped = daMap.skipped_count || 0;
} catch(e) {}

// AC7: detect UPSERT Delivery Attempts failure (continueOnFail)
try {
  const daResult = $('UPSERT Delivery Attempts').first().json;
  if (daResult && daResult.error) {
    delivery_attempts_error = String(daResult.error.message || JSON.stringify(daResult.error)).substring(0, 200);
    delivery_attempts_upserted = 0;
  }
} catch(e) {}

const result = {
  rows_processed: mapData.rows_processed,
  orders_upserted: linkData.orders_upserted,
  packages_inserted: linkData.packages_count,
  rows_skipped: mapData.rows_skipped,
  errors: mapData.errors,
  delivery_attempts_upserted,
  delivery_attempts_skipped,
};
if (delivery_attempts_error) {
  result.delivery_attempts_error = true;
  result.delivery_attempts_error_message = delivery_attempts_error;
}

return [{ json: {
  job_id: jobId,
  patch_body: {
    status: 'completed',
    completed_at: new Date().toISOString(),
    result,
  }
}}];

const error = $input.first().json;
let jobId = null;
try {
  const jobResp = $('Create Job Record').first();
  if (jobResp && jobResp.json) jobId = jobResp.json.id || null;
} catch(e) {}

if (!jobId || jobId === 'null') {
  return [];
}

const errorMessage = String(error.message || error.description || JSON.stringify(error)).substring(0, 1000);

return [{ json: {
  job_id: jobId,
  patch_body: {
    status: 'failed',
    completed_at: new Date().toISOString(),
    error_message: errorMessage
  }
}}];

// Build today's date in both formats needed by DispatchTrack
const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');

return [{ json: {
  date_api: `${yyyy}-${mm}-${dd}`,
  date_url: `${dd}-${mm}-${yyyy}`,
  email: 'contacto@transportesmusan.com',
  base_url: 'https://paris.dispatchtrack.com'
}}];

const html = $input.first().json.data || '';
const match = html.match(/csrf-token.*?content="([^"]+)"/);
if (!match) throw new Error('Could not extract CSRF token — session may be expired');
const dateParams = $('Build Date Params').first().json;
return [{ json: { csrf_token: match[1], ...dateParams }}];

